	             qrystart <= last;
	             qrystart++, 
	             result += RESULT_SPAN) 
	    {
			unsigned int node_start = 0;
	        unsigned int prev = 0;

	        if ((cur == 0) || (qry_match_len < 1)) 
	        {
	            GOROOT(cur);
	            qry_match_len = 1;
	            mustmatch = 0;
	        }

	        char c = GETQCHAR(qrystart + qry_match_len);

	        XPRINTF("In node ("fNID"): starting with %c [%d] =>  \n",
	                NID(cur), c, qry_match_len);

